changeSet.sql:
CREATE TABLE IF NOT EXISTS public.homebrew_reports (
    id          uuid PRIMARY KEY,
    package_id  uuid NOT NULL REFERENCES public.homebrew_packages(id) ON DELETE CASCADE,
    reporter_id uuid NOT NULL REFERENCES public.users(id) ON DELETE CASCADE,
    reason      text NOT NULL,
    status      character varying(20) NOT NULL DEFAULT 'OPEN',
    created_at  timestamp with time zone NOT NULL DEFAULT now(),
    resolved_at timestamp with time zone,
    resolved_by uuid REFERENCES public.users(id) ON DELETE SET NULL
);
CREATE INDEX IF NOT EXISTS idx_homebrew_reports_package ON public.homebrew_reports (package_id);
CREATE INDEX IF NOT EXISTS idx_homebrew_reports_status  ON public.homebrew_reports (status);
